local G = DYCLegendary local GetEntSize = G.GetEntSize local assets = { } local function OnHitLightning(inst, owner, target) inst:Remove() local fx = SpawnPrefab( "dyc_p_lightningstaff_hit" ) fx.Transform:SetPosition(inst:GetPosition():Get()) fx:Remove(0.35) end local function OnHitFire(inst, owner, target) inst:Remove() local fx = SpawnPrefab( "dyc_p_fireball_hit" ) fx.Transform:SetPosition(inst:GetPosition():Get()) fx:Remove(0.24) local fx2 = SpawnPrefab( "dyc_p_fireball_hit2" ) fx2.Transform:SetPosition(inst:GetPosition():Get()) fx2:Remove(0.15) local fx3 = SpawnPrefab( "dyc_p_fireball_hit3" ) fx3.Transform:SetPosition(inst:GetPosition():Get()) fx3:Remove(0.2) end local function OnHitIce(inst, owner, target) inst:Remove() local fx = SpawnPrefab( "dyc_p_iceball_hit" ) fx.Transform:SetPosition(inst:GetPosition():Get()) fx:Remove(0.4) local fx2 = SpawnPrefab( "dyc_p_iceball_hit2" ) fx2.Transform:SetPosition(inst:GetPosition():Get()) fx2:Remove(0.15) end local function common() local inst = CreateEntity() local trans = inst.entity:AddTransform() MakeInventoryPhysics(inst) RemovePhysicsColliders(inst) inst:AddTag( "projectile" ) inst:AddComponent( "projectile" ) inst.persists = false local light = CreateEntity() inst.lightChild = light inst:AddChild(light) light.entity:AddTransform() light.entity:AddLight() light:AddTag( "FX" ) light.persists = false local oldRemove = inst.Remove inst.Remove = function(inst, ...) inst:RemoveChild(light) light.Transform:SetPosition(inst:GetPosition():Get()) light:DoPeriodicTask(FRAMES, function() light.lightRadius = light.lightRadius - FRAMES * 0x2 if light.lightRadius > 0x0 then light.Light:SetRadius(light.lightRadius) else light:Remove() end end) return oldRemove(inst, ...) end return inst end local function lightning() local inst = common() local light = inst.lightChild.Light light:SetColour(0x0 / 0xff, 0x64 / 0xff, 0xff / 0xff) light:SetFalloff(0.5) light:SetIntensity(0.8) light:SetRadius(1.5) inst.lightChild.lightRadius = 1.5 light:Enable(true) inst.components.projectile:SetSpeed(0xf) inst.components.projectile:SetOnHitFn(OnHitLightning) inst.components.projectile:SetOnMissFn(OnHitLightning) inst.components.projectile:SetLaunchOffset({x = 0.8, y = 2.25}) local core = inst:SpawnChild( "dyc_p_lightningstaff_core" ) core:SetPercentage(0.75) local trail = inst:SpawnChild( "dyc_p_lightningstaff_trail" ) local flare = inst:SpawnChild( "dyc_p_lightningstaff_flare" ) flare:SetPercentage(2.5) return inst end local function fireball() local inst = common() local light = inst.lightChild.Light light:SetColour(0xff / 0xff, 0xc8 / 0xff, 0x0 / 0xff) light:SetFalloff(0.5) light:SetIntensity(0.8) light:SetRadius(1.5) inst.lightChild.lightRadius = 1.5 light:Enable(true) inst.components.projectile:SetSpeed(0xf) inst.components.projectile:SetOnHitFn(OnHitFire) inst.components.projectile:SetOnMissFn(OnHitFire) inst.components.projectile:SetLaunchOffset({x = 0.8, y = 2.25}) local core = inst:SpawnChild( "dyc_p_fireball_core" ) local trail = inst:SpawnChild( "dyc_p_fireball_trail" ) local flare = inst:SpawnChild( "dyc_p_fireball_flare" ) return inst end local function iceball() local inst = common() local light = inst.lightChild.Light light:SetColour(0x43 / 0xff, 0xeb / 0xff, 0xff / 0xff) light:SetFalloff(0.5) light:SetIntensity(0.8) light:SetRadius(1.5) inst.lightChild.lightRadius = 1.5 light:Enable(true) inst.components.projectile:SetSpeed(0xf) inst.components.projectile:SetOnHitFn(OnHitIce) inst.components.projectile:SetOnMissFn(OnHitIce) inst.components.projectile:SetLaunchOffset({x = 0.8, y = 2.25}) local core = inst:SpawnChild( "dyc_p_iceball_core" ) local trail = inst:SpawnChild( "dyc_p_iceball_trail" ) local sparkle = inst:SpawnChild( "dyc_p_iceball_sparkle" ) return inst end return Prefab( "common/dyc_projectile_fireball" , fireball, assets), Prefab( "common/dyc_projectile_iceball" , iceball, assets), Prefab( "common/dyc_projectile_lightning" , lightning, assets) 